import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

function Home() {
  const [clientData, setClientData] = useState(null);

  useEffect(() => {
    const loggedInUser = localStorage.getItem('clientUser');
    if (loggedInUser) {
      setClientData(JSON.parse(loggedInUser));
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('clientUser');
    setClientData(null);
    window.location.reload(); 
  };

  return (
    <div className="home-page">
      {/* 1. Hero Section with Working Carousel */}
      <header className="py-5 text-white" style={{ background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)', minHeight: '80vh', display: 'flex', alignItems: 'center' }}>
        <div className="container py-5 text-center text-lg-start">
          <div className="row align-items-center">
            <div className="col-lg-6 mb-5 mb-lg-0">
              <h1 className="display-4 fw-bold mb-3">Build Your Next <span className="text-warning">Big Project</span></h1>
              <p className="lead fs-4 mb-4 opacity-75">Professional web development and UI/UX designs.</p>
              <div className="d-grid gap-3 d-sm-flex">
                <Link to="/services" className="btn btn-warning btn-lg px-5 fw-bold shadow">Explore Services</Link>
              </div>
            </div>

            {/* फोटो स्लाइडर (Carousel) */}
            <div className="col-lg-6">
              <div id="heroCarousel" className="carousel slide shadow-lg rounded-4 overflow-hidden" data-bs-ride="carousel">
                <div className="carousel-inner">
                  <div className="carousel-item active">
                    <img src="https://cdn.pixabay.com" className="d-block w-100" style={{ height: '400px', objectFit: 'cover' }} alt="Slide 1" />
                  </div>
                  <div className="carousel-item">
                    <img src="https://cdn.pixabay.com" className="d-block w-100" style={{ height: '400px', objectFit: 'cover' }} alt="Slide 2" />
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </header>

      {/* 2. Map Section (Nashik Location) */}
      <section id="contact" className="py-5 bg-white">
        <div className="container py-5">
          <h2 className="text-center fw-bold mb-5">Find Us Here</h2>
          <div className="row justify-content-center">
            <div className="col-lg-10">
              <div className="shadow rounded-4 overflow-hidden" style={{ height: '400px' }}>
                <iframe 
                  title="Google Map"
                  src="https://www.google.com" 
                  width="100%" height="100%" style={{ border: 0 }} allowFullScreen="" loading="lazy">
                </iframe>
              </div>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
}

export default Home;
